def check_xml(f,xml):
    """Function that read xml file and validates it"""
    f_open= open(f,'r',encoding="utf8") #opens file, in read mode and encoding is utf-8
    xml_data = xml.read()                #reads the contents of a file 
    data=f_open.read()                   #reads the contents of file after opening it
    f_open.close()                       #closes the file 
    return data == xml_data              #return True if both the data in the two files are equal

